import React, { useState } from 'react';
import styled from 'styled-components';
import { useOrders } from '../context/OrderContext';
import CreateOrderModal from '../modals/CreateOrderModal';

const OrdersContainer = styled.div`
  padding: 20px;
`;

const Heading = styled.h1`
  font-size: 2em;
  margin-bottom: 20px;
`;

const Filters = styled.div`
  display: flex;
  justify-content: space-between;
  margin-bottom: 20px;
`;

const FilterInput = styled.input`
  padding: 10px;
  border: 1px solid #ddd;
  border-radius: 4px;
`;

const Table = styled.table`
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 20px;
`;

const Th = styled.th`
  background-color: #f5f5f5;
  padding: 10px;
  border: 1px solid #ddd;
`;

const Td = styled.td`
  padding: 10px;
  border: 1px solid #ddd;
`;

const Pagination = styled.div`
  display: flex;
  justify-content: center;
  margin-top: 20px;
`;

const PaginationButton = styled.button`
  padding: 10px;
  border: 1px solid #ddd;
  border-radius: 4px;
  margin: 0 5px;
  cursor: pointer;

  &:disabled {
    cursor: not-allowed;
    opacity: 0.5;
  }
`;

const AddOrderButton = styled.button`
  padding: 10px 20px;
  background-color: #28a745;
  color: #fff;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  margin-bottom: 20px;

  &:hover {
    background-color: #218838;
  }
`;

const OrdersPage = () => {
  const { orders, loading, error, addOrder } = useOrders();
  const [searchTerm, setSearchTerm] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [ordersPerPage] = useState(10);
  const [isModalOpen, setIsModalOpen] = useState(false);

  const handleSearchChange = (event) => {
    setSearchTerm(event.target.value);
  };

  const filteredOrders = orders.filter(order =>
    order.customer_name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    order.status.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const indexOfLastOrder = currentPage * ordersPerPage;
  const indexOfFirstOrder = indexOfLastOrder - ordersPerPage;
  const currentOrders = filteredOrders.slice(indexOfFirstOrder, indexOfLastOrder);

  const paginate = (pageNumber) => setCurrentPage(pageNumber);

  const handleOrderCreated = (newOrder) => {
    addOrder(newOrder);
  };

  if (loading) {
    return <p>Loading...</p>;
  }

  if (error) {
    return <p>Error loading orders: {error.message}</p>;
  }

  return (
    <OrdersContainer>
      <Heading>Orders</Heading>

      <AddOrderButton onClick={() => setIsModalOpen(true)}>Add New Order</AddOrderButton>

      <Filters>
	<FilterInput
	  type="text"
	  placeholder="Search orders by customer name or status..."
	  value={searchTerm}
	  onChange={handleSearchChange}
	/>
      </Filters>

      <Table>
	<thead>
	  <tr>
	    <Th>Order ID</Th>
	    <Th>Customer Name</Th>
	    <Th>Date</Th>
	    <Th>Status</Th>
	    <Th>Total Amount</Th>
	  </tr>
	</thead>
	<tbody>
	  {currentOrders.map(order => (
	    <tr key={order.id}>
	      <Td>{order.id}</Td>
	      <Td>{order.customer_name}</Td>
	      <Td>{new Date(order.date).toLocaleDateString()}</Td>
	      <Td>{order.status}</Td>
	      <Td>${order.total_amount}</Td>
            </tr>
	  ))}
	</tbody>
      </Table>

      <Pagination>
	{Array.from({ length: Math.ceil(filteredOrders.length / ordersPerPage) }, (_, index) => (
          <PaginationButton
	    key={index + 1}
	    onClick={() => paginate(index + 1)}
	    disabled={currentPage === index + 1}
	  >
	    {index + 1}
	  </PaginationButton>
	))}
      </Pagination>

      <CreateOrderModal
        isOpen={isModalOpen}
	onClose={() => setIsModalOpen(false)}
	onOrderCreated={handleOrderCreated}
      />
    </OrdersContainer>
  );
};

export default OrdersPage;
