import React, { useState } from 'react';
import PropTypes from 'prop-types';
import { updateProductStock } from '../services/api';
import { Modal, Button, Form } from 'react-bootstrap';

const AddAdjustmentModal = ({ show, handleClose, refreshProducts }) => {
  const [adjustmentData, setAdjustmentData] = useState({
    productId: '',
    quantity: '',
    adjustment_date: '',
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setAdjustmentData({ ...adjustmentData, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await updateProductStock(adjustmentData.productId, { stock: adjustmentData.quantity });
      refreshProducts();
      handleClose();
    } catch (error) {
      console.error('Error updating product stock:', error);
    }
  };

  return (
    <Modal show={show} onHide={handleClose}>
      <Modal.Header closeButton>
	<Modal.Title>Add Stock Adjustment</Modal.Title>
	</Modal.Header>
	<Form onSubmit={handleSubmit}>
	  <Modal.Body>
	    <Form.Group controlId="productId">
	      <Form.Label>Product ID</Form.Label>
	      <Form.Control
	        type="text"
	        name="productId"
	        value={adjustmentData.productId}
	        onChange={handleChange}
	        required
	      />
	    </Form.Group>
	  <Form.Group controlId="quantity">
	    <Form.Label>Quantity</Form.Label>
	    <Form.Control
	      type="number"
	      name="quantity"
	      value={adjustmentData.quantity}
	      onChange={handleChange}
	      required
	    />
	  </Form.Group>
	  <Form.Group controlId="adjustment_date">
	    <Form.Label>Adjustment Date</Form.Label>
	    <Form.Control
	      type="date"
	      name="adjustment_date"
	      value={adjustmentData.adjustment_date}
	      onChange={handleChange}
	      required
	    />
	  </Form.Group>
	</Modal.Body>
	<Modal.Footer>
	  <Button variant="secondary" onClick={handleClose}>
	    Close
	  </Button>
	  <Button type="submit" variant="primary">
	    Save Adjustment
	  </Button>
	</Modal.Footer>
      </Form>
    </Modal>
  );
};

AddAdjustmentModal.propTypes = {
  show: PropTypes.bool.isRequired,
  handleClose: PropTypes.func.isRequired,
  refreshProducts: PropTypes.func.isRequired,
};

export default AddAdjustmentModal;
