import React, { createContext, useState, useEffect } from 'react';
import { fetchTransactions, createTransaction, updateTransaction, deleteTransaction } from '../services/api';

export const TransactionContext = createContext();

const TransactionProvider = ({ children }) => {
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const loadTransactions = async () => {
      try {
	const data = await fetchTransactions();
	setTransactions(data);
      } catch (error) {
	console.error('Failed to fetch transactions:', error);
      } finally {
	setLoading(false);
      }
    };

    loadTransactions();
  }, []);

  const addTransaction = async (transaction) => {
    try {
      const newTransaction = await createTransaction(transaction);
      setTransactions((prevTransactions) => [...prevTransactions, newTransaction]);
    } catch (error) {
      throw new Error('Failed to add transaction');
    }
  };

  const editTransaction = async (id, transaction) => {
    try {
      const updatedTransaction = await updateTransaction(id, transaction);
      setTransactions((prevTransactions) =>
        prevTransactions.map((t) => (t.id === id ? updatedTransaction : t))
      );
    } catch (error) {
      throw new Error('Failed to update transaction');
    }
  };

  const removeTransaction = async (id) => {
    try {
      await deleteTransaction(id);
      setTransactions((prevTransactions) => prevTransactions.filter((t) => t.id !== id));
    } catch (error) {
      throw new Error('Failed to delete transaction');
    }
  };

  return (
    <TransactionContext.Provider value={{ transactions, loading, addTransaction, editTransaction, removeTransaction }}>
      {children}
    </TransactionContext.Provider>
  );
};

export default TransactionProvider;
