import React, { useState, useEffect, useContext } from 'react';
import styled from 'styled-components';
import { fetchInvoices, createInvoice } from '../services/api';
import { AuthContext } from '../context/AuthContext';
import CreateInvoiceModal from '../modals/CreateInvoiceModal';

const InvoicesContainer = styled.div`
  padding: 20px;
`;

const Heading = styled.h1`
  font-size: 2em;
  margin-bottom: 20px;
`;

const Table = styled.table`
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 20px;
`;

const Th = styled.th`
  background-color: #f5f5f5;
  padding: 10px;
  border: 1px solid #ddd;
`;

const Td = styled.td`
  padding: 10px;
  border: 1px solid #ddd;
`;

const Filters = styled.div`
  margin-bottom: 20px;
  display: flex;
  justify-content: space-between;
`;

const FilterInput = styled.input`
  padding: 10px;
  border: 1px solid #ddd;
  border-radius: 4px;
`;

const Pagination = styled.div`
  display: flex;
  justify-content: center;
  margin-top: 20px;
`;

const PaginationButton = styled.button`
  padding: 10px;
  border: 1px solid #ddd;
  border-radius: 4px;
  margin: 0 5px;
  cursor: pointer;

  &:disabled {
    cursor: not-allowed;
    opacity: 0.5;
  }
`;

const AddInvoiceButton = styled.button`
  background-color: #007bff;
  color: white;
  padding: 10px 20px;
  border: none;
  border-radius: 4px;
  cursor: pointer;
  margin-bottom: 20px;

  &:hover {
    background-color: #0056b3;
  }
`;

const InvoicesPage = () => {
  const [invoices, setInvoices] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [invoicesPerPage] = useState(10);
  const [showCreateInvoiceModal, setShowCreateInvoiceModal] = useState(false);
  const { authTokens } = useContext(AuthContext);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const data = await fetchInvoices();
	setInvoices(data);
      } catch (error) {
        console.error('Error fetching invoices:', error);
      }
    };

    fetchData();
  }, [authTokens]);

  const handleSearchChange = (event) => {
    setSearchTerm(event.target.value);
  };

  const handleAddInvoice = async (invoiceData) => {
    try {
      const newInvoice = await createInvoice(invoiceData);
      setInvoices([newInvoice, ...invoices]);
      setShowCreateInvoiceModal(false);
    } catch (error) {
      console.error('Error adding invoice:', error);
    }
  };

  const filteredInvoices = invoices.filter(invoice =>
    invoice.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const indexOfLastInvoice = currentPage * invoicesPerPage;
  const indexOfFirstInvoice = indexOfLastInvoice - invoicesPerPage;
  const currentInvoices = filteredInvoices.slice(indexOfFirstInvoice, indexOfLastInvoice);

  const paginate = (pageNumber) => setCurrentPage(pageNumber);

  return (
    <InvoicesContainer>
      <Heading>Invoices</Heading>

      <Filters>
	<FilterInput
	  type="text"
	  placeholder="Search invoices..."
	  value={searchTerm}
	  onChange={handleSearchChange}
	/>
      </Filters>

      <AddInvoiceButton onClick={() => setShowCreateInvoiceModal(true)}>
        Add Invoice
      </AddInvoiceButton>

      <Table>
	<thead>
	  <tr>
	    <Th>Date</Th>
	    <Th>Description</Th>
	    <Th>Amount</Th>
	    <Th>Status</Th>
	  </tr>
	</thead>
	<tbody>
	  {currentInvoices.map(invoice => (
	    <tr key={invoice.id}>
	      <Td>{invoice.date}</Td>
	      <Td>{invoice.description}</Td>
	      <Td>{invoice.amount}</Td>
	      <Td>{invoice.status}</Td>
	    </tr>
	  ))}
	</tbody>
      </Table>

      <Pagination>
	{Array.from({ length: Math.ceil(filteredInvoices.length / invoicesPerPage) }, (_, index) => (
	  <PaginationButton
	    key={index + 1}
	    onClick={() => paginate(index + 1)}
	    disabled={currentPage === index + 1}
	  >
	    {index + 1}
	  </PaginationButton>
	))}
      </Pagination>

      {showCreateInvoiceModal && (
        <CreateInvoiceModal
	  onClose={() => setShowCreateInvoiceModal(false)}
	  onAddInvoice={handleAddInvoice}
	/>
      )}
    </InvoicesContainer>
  );
};

export default InvoicesPage;
