import axios from 'axios';

const API_URL = '/api/users/';
const AUTH_URL = '/api/users/auth/';

// Login user
export const login = async (username, password) => {
  try {
    // Set up Basic auth header
    const authHeader = 'Basic ' + btoa(username + ':' + password);
    const response = await axios.post(`${AUTH_URL}login/`, {}, {
      headers: { 'Authorization': authHeader }
    });
    // Store credentials securely (this is simplified, consider using more secure methods)
    localStorage.setItem('credentials', btoa(username + ':' + password));
    return response.data;
  } catch (error) {
    throw new Error(error.response?.data?.detail || 'Login failed');
  }
};

// Logout user
export const logout = async () => {
  try {
    await axios.post(`${AUTH_URL}logout/`);
  } finally {
    localStorage.removeItem('credentials');
  }
};

// Register user
export const register = async (username, email, password) => {
  try {
    const response = await axios.post(`${API_URL}users/register/`, {
      username,
      email,
      password,
    });
    return response.data;
  } catch (error) {
    throw new Error(error.response?.data?.detail || 'Registration failed');
  }
};

// Get current user
export const getCurrentUser = async () => {
  const credentials = localStorage.getItem('credentials');
  if (!credentials) {
    throw new Error('Not authenticated');
  }
  try {
    const response = await axios.get(`${API_URL}users/`);
    return response.data;
  } catch (error) {
    throw new Error('Failed to fetch user data');
  }
};

// Axios request interceptor to add Basic auth header
axios.interceptors.request.use(
  async (config) => {
    const credentials = localStorage.getItem('credentials');
    if (credentials) {
      config.headers['Authorization'] = `Basic ${credentials}`;
    }
    return config;
  },
  (error) => {
    Promise.reject(error);
  }
);
