// Function to fetch summary data
export const fetchSummaryData = async () => {
  try {
    const [orders, products, customers, transactions] = await Promise.all([
      axiosInstance.get('/core/orders/'),
      axiosInstance.get('/core/products/'),
      axiosInstance.get('/core/customers/'),
      axiosInstance.get('/transactions/transactions/')
    ]);
    return {
      totalOrders: orders.data.length,
      totalProducts: products.data.length,
      totalCustomers: customers.data.length,
      recentTransactions: transactions.data.slice(0, 5)
    };
  } catch (error) {
    console.error('Error fetching summary data:', error.response?.data || error.message);
    throw error;
  }
};

