import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import styled from 'styled-components';

const SidebarContainer = styled.div`
  width: ${(props) => (props.collapsed ? '80px' : '250px')};
  transition: width 0.3s;
  height: 100vh;
  background-color: #343a40;
  color: white;
  position: fixed;
  display: flex;
  flex-direction: column;
`;

const SidebarHeader = styled.div`
  padding: 20px;
  display: flex;
  justify-content: space-between;
  align-items: center;
`;

const SidebarToggle = styled.button`
  background: none;
  border: none;
  color: white;
  cursor: pointer;
`;

const SidebarLinks = styled.div`
  padding: 20px;
`;

const SidebarLink = styled(Link)`
  color: white;
  text-decoration: none;
  display: block;
  padding: 10px 0;

  &:hover {
    background-color: #495057;
  }
`;

const Sidebar = () => {
  const [collapsed, setCollapsed] = useState(false);

  const toggleSidebar = () => {
    setCollapsed(!collapsed);
  };

  return (
    <SidebarContainer collapsed={collapsed}>
      <SidebarHeader>
        <h3>{collapsed ? 'M' : 'Menu'}</h3>
	<SidebarToggle onClick={toggleSidebar}>
	  {collapsed ? '>' : '<'}
	</SidebarToggle>
      </SidebarHeader>
      <SidebarLinks>
	<SidebarLink to="/">Dashboard</SidebarLink>
	<SidebarLink to="/transactions">Transactions</SidebarLink>
	<SidebarLink to="/invoices">Invoices</SidebarLink>
	<SidebarLink to="/products">Products</SidebarLink>
	<SidebarLink to="/stock-levels">Stock Levels</SidebarLink>
	<SidebarLink to="/orders">Orders</SidebarLink>
	<SidebarLink to="/customers">Customers</SidebarLink>
	<SidebarLink to="/user-roles">User Roles</SidebarLink>
	<SidebarLink to="/reports">Reports</SidebarLink>
      </SidebarLinks>
    </SidebarContainer>
  );
};

export default Sidebar;
