import React, { useState, useEffect } from 'react';
import styled from 'styled-components';
import { fetchTransactions } from '../services/api';
import { CSVLink } from 'react-csv';

const TransactionsContainer = styled.div`
  padding: 20px;
`;

const Heading = styled.h1`
  font-size: 2em;
  margin-bottom: 20px;
`;

const Table = styled.table`
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 20px;
`;

const Th = styled.th`
  background-color: #f5f5f5;
  padding: 10px;
  border: 1px solid #ddd;
`;

const Td = styled.td`
  padding: 10px;
  border: 1px solid #ddd;
`;

const Filters = styled.div`
  margin-bottom: 20px;
  display: flex;
  justify-content: space-between;
`;

const FilterInput = styled.input`
  padding: 10px;
  border: 1px solid #ddd;
  border-radius: 4px;
`;

const Pagination = styled.div`
  display: flex;
  justify-content: center;
  margin-top: 20px;
`;

const PaginationButton = styled.button`
  padding: 10px;
  border: 1px solid #ddd;
  border-radius: 4px;
  margin: 0 5px;
  cursor: pointer;

  &:disabled {
    cursor: not-allowed;
    opacity: 0.5;
  }
`;

const BulkUpdateButton = styled.button`
  padding: 10px;
  border: 1px solid #ddd;
  border-radius: 4px;
  cursor: pointer;
  margin-right: 10px;
`;

const TransactionsPage = () => {
  const [transactions, setTransactions] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [transactionsPerPage] = useState(10);
  const [selectedTransactions, setSelectedTransactions] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const data = await fetchTransactions();
	setTransactions(data);
      } catch (error) {
	console.error('Error fetching transactions:', error);
      }
    };

    fetchData();
  }, []);

  const handleSearchChange = (event) => {
    setSearchTerm(event.target.value);
  };

  const handleCheckboxChange = (transactionId) => {
    setSelectedTransactions(prevState => {
      if (prevState.includes(transactionId)) {
        return prevState.filter(id => id !== transactionId);
      } else {
	return [...prevState, transactionId];
      }
    });
  };

  const handleBulkUpdate = async () => {
    try {
      await updateTransactions(selectedTransactions);
      // Refresh data after update
      const data = await fetchTransactions();
      setTransactions(data);
      setSelectedTransactions([]);
    } catch (error) {
      console.error('Error updating transactions:', error);
    }
  };

  const filteredTransactions = transactions.filter(transaction =>
    transaction.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const indexOfLastTransaction = currentPage * transactionsPerPage;
  const indexOfFirstTransaction = indexOfLastTransaction - transactionsPerPage;
  const currentTransactions = filteredTransactions.slice(indexOfFirstTransaction, indexOfLastTransaction);

  const paginate = (pageNumber) => setCurrentPage(pageNumber);

  return (
    <TransactionsContainer>
      <Heading>Transactions</Heading>

      <Filters>
        <FilterInput
	  type="text"
	  placeholder="Search transactions..."
	  value={searchTerm}
	  onChange={handleSearchChange}
	/>
	<div>
	  <BulkUpdateButton onClick={handleBulkUpdate}>Bulk Update</BulkUpdateButton>
	  <CSVLink data={transactions} filename="transactions.csv">Export CSV</CSVLink>
	</div>
      </Filters>

      <Table>
	<thead>
	  <tr>
	    <Th>Date</Th>
	    <Th>Description</Th>
	    <Th>Amount</Th>
	    <Th>Transaction Type</Th>
	    <Th>Status</Th>
	    <Th>Category</Th>
	    <Th>Customer</Th>
	  </tr>
	</thead>
	<tbody>
	  {currentTransactions.map(transaction => (
	    <tr key={transaction.id}>
	      <Td>
		<input
		  type="checkbox"
		  checked={selectedTransactions.includes(transaction.id)}
		  onChange={() => handleCheckboxChange(transaction.id)}
		/>
	      </Td>
	      <Td>{transaction.date}</Td>
	      <Td>{transaction.description}</Td>
	      <Td>{transaction.amount}</Td>
	      <Td>{transaction.transaction_type}</Td>
	      <Td>{transaction.status}</Td>
	      <Td>{transaction.category}</Td>
	      <Td>{transaction.customer}</Td>
	    </tr>
	  ))}
	</tbody>
      </Table>

      <Pagination>
	{Array.from({ length: Math.ceil(filteredTransactions.length / transactionsPerPage) }, (_, index) => (
	  <PaginationButton
	    key={index + 1}
	    onClick={() => paginate(index + 1)}
	    disabled={currentPage === index + 1}
	  >
	    {index + 1}
	  </PaginationButton>
	))}
      </Pagination>
    </TransactionsContainer>
  );
};

export default TransactionsPage;
